local GUIWarning = class("UIWarning", IGUILayout)

function GUIWarning:onLoad()
    self.subWarningAlpha = true
    self.warningAlpha = 0
    self.hideWarning = false

    self.llWarning = self:getChildWindow("TowerDefenseWarning", GUIType.Layout)
    self.llWarning:SetVisible(false)
end


function GUIWarning:onTick(frameTime)
    if self.llWarning:IsVisible() then
        self:upWarningAlpha()
    end
end

function GUIWarning:upWarningAlpha()
    if self.subWarningAlpha then
        self.warningAlpha = self.warningAlpha - 0.011
        if self.warningAlpha <= 0.4 and self.hideWarning == false then
            self.subWarningAlpha = false
        elseif self.hideWarning and self.warningAlpha <= 0 then
            self.hideWarning = false
            self.llWarning:SetVisible(false)
        end
    else
        self.warningAlpha = self.warningAlpha + 0.016
        if self.warningAlpha >= 1.1 then
            self.subWarningAlpha = true
        end
    end
    self.llWarning:SetAlpha(self.warningAlpha)
end

function GUIWarning:showWarning()
    self.warningAlpha = 0.3
    self.llWarning:SetAlpha(self.warningAlpha)
    self.subWarningAlpha = false
    SoundUtil.playSound(908)
    self.llWarning:SetVisible(true)
    LuaTimer:schedule(function()
        self.hideWarning = true
    end, 3000)
end

return GUIWarning